-- V56 — 2026-06-12: agent_knowledge id=38 — flat-mode / block_select steer.
--
-- Background:
--   SLASH-13 ("每個 recipe 的 APC etch_time_offset box plot") repeatedly
--   handover'd because KIMI chose block_unnest on the nested APC dict and
--   死-spiraled on APC vs APC.parameters path semantics. The 1/3 run that
--   succeeded used block_select instead (correct x='recipe_id'). This entry
--   makes that the deliberate choice, not luck — steering "per-dimension
--   distribution/comparison chart" intents toward nested=false flat mode or
--   block_select, away from block_unnest on nested dicts.
--
--   Ships with the validated 1024-dim embedding so fresh deploys get an
--   immediate semantic match (Flyway is disabled in prod — apply via psql,
--   see memory feedback_flyway_disabled_in_prod).
--
-- Idempotent: guarded by NOT EXISTS on title.

INSERT INTO public.agent_knowledge (id, user_id, scope_type, scope_value, title, body, priority, active, source, embedding, uses, last_used_at, created_at, updated_at) SELECT 38, 1, 'global', NULL, '參數分佈 / 對比 chart (box/bar/scatter by 維度) — 用 flat-mode 或 block_select，別 unnest 巢狀 dict', '當 user 要看「每個 X 的 Y 參數分佈 / 比較」類圖表 (box plot, bar, scatter, violin)，例如：
  - 「每個 recipe 的 APC etch_time_offset 分佈」
  - 「各 chamber 的 pressure box plot」
  - 「比較各 lot 的 alignment_x」

block_process_history 回傳的 APC / RECIPE / DC / FDC 是**巢狀物件**(nested dict)。
要把巢狀維度的某個 scalar 參數 (如 etch_time_offset) + 分組維度 (如 recipe) 攤平給
chart 用，**有兩條好路，都不要走 block_unnest**：

✓ **首選 (2 nodes) — flat mode**:
  1. block_process_history(tool_id=''...'', time_range=''...'', nested=false)
  2. <chart_block>(x=''<dim>_id'', y=''<prefix>_<param>'')
  flat mode 自動把巢狀維度攤成 top-level 欄位：
    RECIPE.objectID            -> recipe_id
    RECIPE.parameters.<k>      -> recipe_<k>
    APC.objectID               -> apc_id
    APC.parameters.<k>         -> apc_<k>   (e.g. apc_etch_time_offset)
    DC.chamberID               -> dc_chamber_id
    FDC.parameters.<k>         -> fdc_<k>

✓ **次選 (3 nodes) — block_select 抽 path**（已用 nested=true 或想保留其他欄位時）:
  1. block_process_history(...)           # nested=true default
  2. block_select(fields=[
       {path:''RECIPE.objectID'', as:''recipe_id''},
       {path:''APC.parameters.etch_time_offset'', as:''etch_time_offset''}])
  3. <chart_block>(x=''recipe_id'', y=''etch_time_offset'')

⛔ **不要** 用 block_unnest(column=''APC.parameters'') 或 column=''APC'' 去攤巢狀 dict。
   block_unnest 是給「array 欄位展開成多列」用的 (如 spc_charts list)，
   對 nested dict 的 path 語意 LLM 很容易搞錯 (APC vs APC.parameters 反覆鬼打牆)，
   會把 round budget 燒光。要抽 nested scalar 一律用 block_select / block_pluck / nested=false。

關鍵：chart 的 x 要對應 user 講的「每個 X」的維度 (recipe -> recipe_id)，
不要拿 step / toolID 之類別的欄位硬湊 — 先確認該維度欄位真的存在 (看 canvas cols)。', 'high', true, 'manual', '[0.005516,0.054535,-0.047852,0.019302,-0.017365,-0.032898,-0.011192,-0.059082,-0.026062,-0.002403,0.032196,0.018478,-0.007698,-0.019714,0.017487,-0.006153,0.041565,0.008675,0.034546,-0.033508,-0.04129,0.003653,0.082764,-0.040894,0.031113,-0.028839,0.02449,0.043152,0.007328,-0.007576,-0.004826,-0.006714,-0.000435,0.02861,-0.026627,-0.037231,0.024872,-0.025299,0.019913,0.012756,-0.023117,-0.018784,-0.00721,0.026901,0.022141,-0.025467,0.010101,-0.015472,0.028137,0.031708,0.00441,-0.024582,0.014648,-0.002645,0.011414,0.006119,-0.030136,-0.045319,0.068604,-0.017639,0.012932,0.014977,0.043396,-0.01133,0.043945,0.050659,0.016495,0.062408,0.012146,0.02095,0.028702,0.024994,0.024902,-0.010971,-0.056427,-0.021301,0.017349,-0.02269,0.007874,0.035645,-0.009651,0.002193,-0.003588,-0.00592,0.045227,-0.004257,-0.009346,0.005108,-0.003588,-0.033844,0.022308,0.000299,-0.053558,0.02536,-0.006996,-0.020813,-0.001041,0.014793,0.013268,0.013626,0.027206,-0.012947,0.004604,0.009491,0.01548,0.031204,0.018585,-0.006332,0.013458,0.014923,-0.016632,0.011505,-0.006142,-0.028275,-0.030762,-0.01889,0.011406,0.001334,-0.009315,0.000735,-0.001408,-0.012192,-0.008827,0.040344,0.014336,-0.062744,0.021057,-0.038513,-0.035004,0.012405,-0.0215,0.010216,0.035767,-0.015099,0.018768,0.003546,-0.002501,0.001573,0.067322,0.040649,0.032715,0.032806,0.009293,0.033691,-0.008644,-0.030579,0.030106,0.015991,-0.017242,-0.008499,-0.025467,-0.03598,-0.00135,-0.004616,0.05423,-0.001946,0.000127,-0.025269,-0.004929,-0.015175,-0.013725,-0.081238,0.01622,-0.027328,0.019547,-0.044312,0.015762,-0.023697,0.007713,0.049591,-0.00629,-0.004257,-0.000685,-0.010521,-0.028046,-0.004448,0.009888,0.015808,0.016724,0.056152,-0.005562,-0.001418,-0.045898,-0.089111,0.028198,-0.003473,-0.018311,0.006855,0.016373,0.031494,0.004887,-0.041534,-0.064453,-0.039093,-0.060669,0.023422,0.045746,-0.031464,-0.006035,0.07489,-0.013237,-0.008774,0.040222,-0.00